use std::collections::HashSet;impl Solution { pub fn minimum_teachings(n: i32, langs: Vec<Vec<i32>>, friends: Vec<Vec<i32>>) -> i32 { let black_l = langs.iter().map(|v| v.iter().cloned().collect::<HashSet<i32>>()).collect::<Vec<_>>(); let black_bad = friends.into_iter().filter(|f| black_l[f[0] as usize - 1].intersection(&black_l[f[1] as usize - 1]).next().is_none()).flat_map(|f| vec![f[0], f[1]]).collect::<HashSet<i32>>(); if black_bad.is_empty() { 0 } else { (1..=n).map(|i| black_bad.iter().filter(|&&u| !black_l[u as usize - 1].contains(&i)).count()).min().unwrap() as i32 } } }